import (
	"container/heap"
)

type Item struct {
	negMinCost int64
	totalCost  int64
	node       int
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].negMinCost < pq[j].negMinCost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(edges [][]int64, online []bool, k int64) int64 {
	n := len(online)
	adj := make([][][2]int64, n)
	for _, edge := range edges {
		u, v, cost := edge[0], edge[1], edge[2]
		adj[u] = append(adj[u], [2]int64{v, cost})
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Item{0, 0, 0})

	maxScore := int64(-1)

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		currentMinCost := -item.negMinCost
		u := item.node

		if u == n-1 {
			if item.totalCost <= k {
				if currentMinCost > maxScore {
					maxScore = currentMinCost
				}
			}
			continue
		}

		for _, edge := range adj[u] {
			v, cost := edge[0], edge[1]
			if !online[v] && v != n-1 {
				continue
			}
			newTotal := item.totalCost + cost
			if newTotal > k {
				continue
			}
			var newMin int64
			if currentMinCost != 0 {
				newMin = min(currentMinCost, cost)
			} else {
				newMin = cost
			}
			heap.Push(&pq, &Item{-newMin, newTotal, int(v)})
		}
	}

	return maxScore
}

func min(a, b int64) int64 {
	if a < b {
		return a
	}
	return b
